Here are the public test cases for feature12_security_context:
{
  "cases": [
    {
      "input": {
        "annotations": {},
        "op": "security_context"
      },
      "expected_output": "{\"security_context\":{\"run_as_user\":100,\"run_as_group\":1000,\"run_as_non_root\":true,\"read_only_root_filesystem\":true,\"allow_privilege_escalation\":false,\"capabilities_drop\":[\"ALL\"]},\"status\":\"ok\"}\n"
    },
    {
      "input": {
        "annotations": {
          "vault.hashicorp.com/agent-run-as-group": "1001",
          "vault.hashicorp.com/agent-run-as-user": "1001"
        },
        "op": "security_context"
      },
      "expected_output": "{\"security_context\":{\"run_as_user\":1001,\"run_as_group\":1001,\"run_as_non_root\":true,\"read_only_root_filesystem\":true,\"allow_privilege_escalation\":false,\"capabilities_drop\":[\"ALL\"]},\"status\":\"ok\"}\n"
    },
    {
      "input": {
        "annotations": {
          "vault.hashicorp.com/agent-run-as-group": "0",
          "vault.hashicorp.com/agent-run-as-user": "0"
        },
        "op": "security_context"
      },
      "expected_output": "{\"security_context\":{\"run_as_user\":0,\"run_as_group\":0,\"run_as_non_root\":false,\"read_only_root_filesystem\":true,\"allow_privilege_escalation\":false,\"capabilities_drop\":[\"ALL\"]},\"status\":\"ok\"}\n"
    },
    {
      "input": {
        "set_security_context": false,
        "op": "security_context"
      },
      "expected_output": "{\"security_context\":null,\"status\":\"ok\"}\n"
    },
    {
      "input": {
        "app_run_as_user": 123456,
        "same_id": true,
        "op": "security_context"
      },
      "expected_output": "{\"security_context\":{\"run_as_user\":123456,\"run_as_group\":1000,\"run_as_non_root\":true,\"read_only_root_filesystem\":true,\"allow_privilege_escalation\":false,\"capabilities_drop\":[\"ALL\"]},\"status\":\"ok\"}\n"
    }
  ],
  "description": "Derive the agent container's security context from configuration and annotations. By default it pins a non-root run-as user and group, marks the filesystem read-only, drops all capabilities and forbids privilege escalation. Run-as user/group are overridable by annotation; setting either to 0 flips the non-root flag to false. Disabling the set-security-context flag yields no security context at all. In same-user mode the agent adopts the application container's declared user id."
}
